+
+func unixTimeFromMaybeMillis(value float64) time.Time {
+	secs := int64(value)
+	if secs <= 0 {
+		return time.Time{}
+	}
+	if secs > 1_000_000_000_000 {
+		return time.UnixMilli(secs)
+	}
+	return time.Unix(secs, 0)
+}
